import { useState, useEffect, useCallback } from "react";
import { useSearchParams } from "react-router-dom";
import MapView from "../components/MapView";
import PlaceSidebar from "../components/PlaceSidebar";
import api from "../utils/api";
import { CATEGORY_OPTIONS } from "../utils/categories";
import { PinIcon } from "../components/UiIcons";

export default function HomePage() {
  const [params, setParams] = useSearchParams();
  const [places, setPlaces] = useState([]);
  const [loading, setLoading] = useState(true);
  const [userPos, setUserPos] = useState(null);
  const [mapCenter, setMapCenter] = useState(null);
  const [mapZoom, setMapZoom] = useState(13);
  const [radius, setRadius] = useState(5);
  const [search, setSearch] = useState("");
  const [selectedId, setSelectedId] = useState("");
  const cat = params.get("category") || "all";

  const load = useCallback(async () => {
    setLoading(true);
    try {
      let url = "/places";
      const q = new URLSearchParams();
      if (cat !== "all") q.set("category", cat);
      if (search) q.set("search", search);
      if (q.toString()) url += "?" + q;

      const { data } = await api.get(url);
      setPlaces(data.data || []);

      if (!selectedId && data.data?.[0]) {
        setSelectedId(data.data[0]._id);
      }
    } catch {
      setPlaces([]);
    }
    setLoading(false);
  }, [cat, search, selectedId]);

  useEffect(() => {
    load();
  }, [load]);

  const getLocation = () => {
    navigator.geolocation?.getCurrentPosition(async (pos) => {
      const { latitude: lat, longitude: lng } = pos.coords;
      setUserPos([lat, lng]);
      setMapCenter([lat, lng]);
      setMapZoom(14);
      try {
        const { data } = await api.get(
          `/places/nearby?lat=${lat}&lng=${lng}&radius=${radius}${cat !== "all" ? `&category=${cat}` : ""}`,
        );
        setPlaces(data.data || []);
        if (data.data?.[0]) {
          setSelectedId(data.data[0]._id);
          setMapCenter([data.data[0].location.lat, data.data[0].location.lng]);
          setMapZoom(15);
        }
      } catch {}
    });
  };

  useEffect(() => {
    getLocation();
  }, []); // eslint-disable-line

  useEffect(() => {
    if (!userPos) return;
    getLocation();
  }, [radius]); // eslint-disable-line

  const setCat = async (key) => {
    const next = new URLSearchParams(params);
    if (key === "all") next.delete("category");
    else next.set("category", key);
    setParams(next);

    if (!userPos) {
      const filtered =
        key === "all" ? places : places.filter((p) => p.category === key);
      setPlaces(filtered);
      if (filtered[0]) {
        setSelectedId(filtered[0]._id);
        setMapCenter([filtered[0].location.lat, filtered[0].location.lng]);
        setMapZoom(15);
      }
      return;
    }

    try {
      const [lat, lng] = userPos;
      const { data } = await api.get(
        `/places/nearby?lat=${lat}&lng=${lng}&radius=${radius}${key !== "all" ? `&category=${key}` : ""}`,
      );
      setPlaces(data.data || []);

      if (data.data?.[0]) {
        setSelectedId(data.data[0]._id);
        setMapCenter([data.data[0].location.lat, data.data[0].location.lng]);
        setMapZoom(15);
      } else {
        setMapCenter([lat, lng]);
        setMapZoom(14);
      }
    } catch {}
  };

  const selectPlace = (place) => {
    setSelectedId(place._id);
    setMapCenter([place.location.lat, place.location.lng]);
    setMapZoom(16);
  };

  return (
    <div
      style={{
        height: "calc(100vh - 56px)",
        display: "flex",
        flexDirection: "column",
      }}
    >
      <div
        style={{
          padding: "10px 20px",
          background: "var(--bg)",
          borderBottom: "1px solid var(--border)",
          display: "flex",
          gap: 8,
          alignItems: "center",
          overflowX: "auto",
        }}
      >
        {CATEGORY_OPTIONS.map((c) => {
          const CategoryIcon = c.icon;
          return (
            <button
              key={c.value}
              onClick={() => setCat(c.value)}
              style={{
                padding: "6px 16px",
                borderRadius: 20,
                fontSize: 13,
                fontWeight: 500,
                cursor: "pointer",
                border: "1px solid",
                whiteSpace: "nowrap",
                background: cat === c.value ? "var(--teal)" : "var(--card)",
                color: cat === c.value ? "#fff" : "var(--muted)",
                borderColor: cat === c.value ? "var(--teal)" : "var(--border)",
              }}
            >
              <span style={{ display: "inline-flex", marginRight: 6 }}>
                <CategoryIcon size={14} />
              </span>
              {c.label}
            </button>
          );
        })}

        <div
          style={{
            marginLeft: "auto",
            display: "flex",
            gap: 8,
            alignItems: "center",
          }}
        >
          <input
            placeholder="Хайх..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={{
              padding: "6px 12px",
              background: "var(--card)",
              border: "1px solid var(--border)",
              borderRadius: 8,
              color: "var(--text)",
              fontSize: 13,
              width: 180,
            }}
          />

          <input
            type="number"
            value={radius}
            onChange={(e) => setRadius(Number(e.target.value) || 5)}
            style={{
              width: 74,
              padding: "6px 10px",
              background: "var(--card)",
              border: "1px solid var(--border)",
              borderRadius: 8,
              color: "var(--text)",
              fontSize: 13,
            }}
            title="Ойролцоох радиус (км)"
          />

          <button
            onClick={getLocation}
            style={{
              padding: "6px 14px",
              background: "var(--blue)",
              color: "#fff",
              border: "none",
              borderRadius: 8,
              cursor: "pointer",
              fontSize: 13,
              whiteSpace: "nowrap",
            }}
          >
            <span style={{ display: "inline-flex", marginRight: 6 }}>
              <PinIcon size={14} />
            </span>
            Байршил
          </button>
          <button
            onClick={showMyRange}
            title="Таны одоогийн радиус руу шилжих"
            style={{
              padding: "6px 14px",
              background: "var(--teal)",
              color: "#fff",
              border: "none",
              borderRadius: 8,
              cursor: "pointer",
              fontSize: 13,
              whiteSpace: "nowrap",
            }}
          >
            Миний хүрээ
          </button>
        </div>
      </div>

      <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>
        <div style={{ flex: 1, position: "relative" }}>
          <MapView
            businesses={places}
            userPos={userPos}
            center={mapCenter}
            zoom={mapZoom}
          />
        </div>

        <PlaceSidebar
          places={places}
          selectedId={selectedId}
          loading={loading}
          onSelect={selectPlace}
        />
      </div>
    </div>
  );
}
